-- Add a reusable 150-sentence office communication deck with highlighted vocabulary and audio.
insert into public.template_decks (slug, name, description, level)
values (
  'giao-tiep-cong-so-150-cau',
  'Giao tiếp công sở - 150 câu',
  '150 câu tiếng Trung theo tình huống công sở: trao đổi công việc, giao nhiệm vụ, báo tiến độ, họp, xin nghỉ và nhắn tin với đồng nghiệp. Mỗi câu có pinyin, nghĩa tiếng Việt, từ mới được highlight và audio tạo sẵn.',
  'Luyện câu'
)
on conflict (slug) do update
set name = excluded.name, description = excluded.description, level = excluded.level;

with target_deck as (
  select id from public.template_decks where slug = 'giao-tiep-cong-so-150-cau'
)
insert into public.template_sentence_cards (
  template_deck_id, sentence_cn, sentence_pinyin, sentence_vi,
  vocab_json, sentence_audio_url, position
)
select
  target_deck.id, card.sentence_cn, card.sentence_pinyin,
  card.sentence_vi, card.vocab_json::jsonb,
  card.sentence_audio_url, card.position
from target_deck
cross join (
  values
    ('早上好，今天的会议几点开始？', 'Zǎoshang hǎo, jīntiān de huìyì jǐ diǎn kāishǐ?', 'Chào buổi sáng, cuộc họp hôm nay bắt đầu lúc mấy giờ?', '[{"chinese":"会议","pinyin":"huìyì","meaning_vi":"cuộc họp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-74fe50672f4a9b0121acbd60.mp3', 1),
    ('请帮我确认一下这份报告的内容是否完整。', 'Qǐng bāng wǒ quèrèn yíxià zhè fèn bàogào de nèiróng shìfǒu wánzhěng.', 'Xin vui lòng giúp tôi xác nhận lại xem nội dung của báo cáo này có đầy đủ không.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"报告","pinyin":"bàogào","meaning_vi":"báo cáo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5af96cbf039c72140ceaa4c1.mp3', 2),
    ('今天中午我们一起去吃饭，可以吗？', 'Jīntiān zhōngwǔ wǒmen yīqǐ qù chīfàn, kěyǐ ma?', 'Trưa nay chúng ta đi ăn cùng nhau được không?', '[{"chinese":"中午","pinyin":"zhōngwǔ","meaning_vi":"buổi trưa"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-55b38e11da2aec4161a58529.mp3', 3),
    ('我需要借用一下那份文件，可以吗？', 'Wǒ xūyào jièyòng yíxià nà fèn wénjiàn, kěyǐ ma?', 'Tôi cần mượn tạm tài liệu đó được không?', '[{"chinese":"借用","pinyin":"jièyòng","meaning_vi":"mượn, dùng tạm"},{"chinese":"文件","pinyin":"wénjiàn","meaning_vi":"tài liệu, văn kiện"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d044e0b740456745b03020ce.mp3', 4),
    ('下午的项目进展我们需要当面讨论。', 'Xiàwǔ de xiàngmù jìnzhǎn wǒmen xūyào dāngmiàn tǎolùn.', 'Chúng ta cần trao đổi trực tiếp về tiến độ dự án vào buổi chiều.', '[{"chinese":"项目","pinyin":"xiàngmù","meaning_vi":"dự án"},{"chinese":"进展","pinyin":"jìnzhǎn","meaning_vi":"tiến triển, tiến độ"},{"chinese":"当面","pinyin":"dāngmiàn","meaning_vi":"trực diện, gặp mặt trao đổi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-61fcface0a3bccd947838953.mp3', 5),
    ('下班前请记得整理好你的办公桌。', 'Xiàbān qián qǐng jìde zhěnglǐ hǎo nǐ de bàngōng zhuō.', 'Trước khi tan làm, xin nhớ dọn dẹp bàn làm việc của bạn.', '[{"chinese":"下班","pinyin":"xiàbān","meaning_vi":"tan làm"},{"chinese":"整理","pinyin":"zhěnglǐ","meaning_vi":"sắp xếp, dọn dẹp"},{"chinese":"办公桌","pinyin":"bàngōng zhuō","meaning_vi":"bàn làm việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2354499c8d6a0487b5c5582f.mp3', 6),
    ('请把最新的文件发送给我，谢谢！', 'Qǐng bǎ zuìxīn de wénjiàn fāsòng gěi wǒ, xièxiè!', 'Vui lòng gửi cho tôi tài liệu mới nhất, cảm ơn!', '[{"chinese":"最新","pinyin":"zuìxīn","meaning_vi":"mới nhất"},{"chinese":"发送","pinyin":"fāsòng","meaning_vi":"gửi đi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-724535f50f467ad3ea96d0a1.mp3', 7),
    ('请确认您已经收到我发的文件。', 'Qǐng quèrèn nín yǐjīng shōudào wǒ fā de wénjiàn.', 'Xin xác nhận bạn đã nhận được tài liệu tôi gửi.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"收到","pinyin":"shōudào","meaning_vi":"nhận, nhận được"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-80bd489e51f7e4cb6db28be8.mp3', 8),
    ('请问什么时候方便召开项目会议？', 'Qǐngwèn shénme shíhòu fāngbiàn zhàokāi xiàngmù huìyì?', 'Xin hỏi khi nào thuận tiện tổ chức họp dự án?', '[{"chinese":"召开","pinyin":"zhàokāi","meaning_vi":"tổ chức (họp)"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f5d19cf02e0aae9f22dfac74.mp3', 9),
    ('工作交接完成后，请通知相关人员确认。', 'Gōngzuò jiāojiē wánchéng hòu, qǐng tōngzhī xiāngguān rényuán quèrèn.', 'Sau khi bàn giao công việc xong, xin thông báo cho các nhân viên liên quan xác nhận.', '[{"chinese":"工作交接","pinyin":"gōngzuò jiāojiē","meaning_vi":"bàn giao công việc"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"},{"chinese":"相关人员","pinyin":"xiāngguān rényuán","meaning_vi":"nhân viên liên quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-807f251cef5aeeaee9de1d35.mp3', 10),
    ('会议结束后，请大家填写反馈表。', 'Huìyì jiéshù hòu, qǐng dàjiā tiánxiě fǎnkuì biǎo.', 'Sau khi cuộc họp kết thúc, xin mọi người điền phiếu phản hồi.', '[{"chinese":"会议结束","pinyin":"huìyì jiéshù","meaning_vi":"cuộc họp kết thúc"},{"chinese":"反馈表","pinyin":"fǎnkuì biǎo","meaning_vi":"phiếu phản hồi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e66ba332bdf8b9ccafb7f3ef.mp3', 11),
    ('请把今天的工作计划发给我参考。', 'Qǐng bǎ jīntiān de gōngzuò jìhuà fā gěi wǒ cānkǎo.', 'Vui lòng gửi kế hoạch công việc hôm nay cho tôi tham khảo.', '[{"chinese":"工作计划","pinyin":"gōngzuò jìhuà","meaning_vi":"kế hoạch công việc"},{"chinese":"参考","pinyin":"cānkǎo","meaning_vi":"tham khảo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e1a475c67d0528cb70438f5b.mp3', 12),
    ('午休时间到了，请大家及时休息。', 'Wǔxiū shíjiān dào le, qǐng dàjiā jíshí xiūxí.', 'Đến giờ nghỉ trưa rồi, mọi người nghỉ ngơi một chút nhé.', '[{"chinese":"午休时间","pinyin":"wǔxiū shíjiān","meaning_vi":"giờ nghỉ trưa"},{"chinese":"及时","pinyin":"jíshí","meaning_vi":"kịp thời"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-345f2b93b9baae695adb63ca.mp3', 13),
    ('请尽快完成这项任务并告知我进度。', 'Qǐng jǐnkuài wánchéng zhè xiàng rènwu bìng gàozhī wǒ jìndù.', 'Xin vui lòng hoàn thành nhiệm vụ này càng sớm càng tốt và báo cho tôi tiến độ.', '[{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"任务","pinyin":"rènwu","meaning_vi":"nhiệm vụ"},{"chinese":"进度","pinyin":"jìndù","meaning_vi":"tiến độ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-16723a24b5f485e0ce90af3e.mp3', 14),
    ('会议资料我已经打印好放在会议室了。', 'Huìyì zīliào wǒ yǐjīng dǎyìn hǎo fàng zài huìyì shì le.', 'Tài liệu họp tôi đã in xong và đặt ở phòng họp rồi.', '[{"chinese":"会议资料","pinyin":"huìyì zīliào","meaning_vi":"tài liệu họp"},{"chinese":"打印","pinyin":"dǎyìn","meaning_vi":"in ấn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-7bcecae6006cac5c6540c5f2.mp3', 15),
    ('请提前安排好明天的日程，谢谢配合。', 'Qǐng tíqián ānpái hǎo míngtiān de rìchéng, xièxie pèihé.', 'Xin sắp xếp trước lịch trình ngày mai, cảm ơn sự phối hợp.', '[{"chinese":"提前","pinyin":"tíqián","meaning_vi":"trước thời hạn"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"},{"chinese":"日程","pinyin":"rìchéng","meaning_vi":"lịch trình"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8e0f8c34a8922b576a34cbf5.mp3', 16),
    ('如果有任何问题，请尽快联系我。', 'Rúguǒ yǒu rènhé wèntí, qǐng jǐnkuài liánxì wǒ.', 'Nếu có bất kỳ vấn đề gì, xin hãy liên hệ tôi sớm nhất có thể.', '[{"chinese":"问题","pinyin":"wèntí","meaning_vi":"vấn đề"},{"chinese":"尽快","pinyin":"jǐnkuài","meaning_vi":"càng nhanh càng tốt"},{"chinese":"联系","pinyin":"liánxì","meaning_vi":"liên lạc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-698bb42895c20eb4b87f05a5.mp3', 17),
    ('请各位准时参加上午的部门会议。', 'Qǐng gèwèi zhǔnshí cānjiā shàngwǔ de bùmén huìyì.', 'Mọi người vui lòng tham dự họp bộ phận buổi sáng đúng giờ.', '[{"chinese":"准时","pinyin":"zhǔnshí","meaning_vi":"đúng giờ"},{"chinese":"部门","pinyin":"bùmén","meaning_vi":"bộ phận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-16b9f2316672d908411c10f5.mp3', 18),
    ('我已完成今日的工作，请您审阅。', 'Wǒ yǐ wánchéng jīnrì de gōngzuò, qǐng nín shěnyuè.', 'Tôi đã hoàn thành công việc hôm nay, xin bạn xem xét.', '[{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"审阅","pinyin":"shěnyuè","meaning_vi":"xem xét, duyệt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d6584af92bcd227536dcd0d2.mp3', 19),
    ('稍后我会把文件传给您，请注意查收。', 'Shāohòu wǒ huì bǎ wénjiàn chuán gěi nín, qǐng zhùyì cháshōu.', 'Sau đây tôi sẽ gửi tài liệu cho bạn, xin chú ý kiểm tra nhận.', '[{"chinese":"稍后","pinyin":"shāohòu","meaning_vi":"chút nữa, lát nữa"},{"chinese":"传","pinyin":"chuán","meaning_vi":"gửi, truyền"},{"chinese":"注意","pinyin":"zhùyì","meaning_vi":"chú ý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-6235dbed59f3e51047f4a397.mp3', 20),
    ('大家辛苦了，今天的工作就先到这里。', 'Dàjiā xīnkǔ le, jīntiān de gōngzuò jiù xiān dào zhèlǐ.', 'Mọi người đã vất vả rồi, công việc hôm nay tạm thời đến đây thôi.', '[{"chinese":"辛苦","pinyin":"xīnkǔ","meaning_vi":"vất vả"},{"chinese":"先","pinyin":"xiān","meaning_vi":"trước, tạm thời"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f99c278f496ab547a84de657.mp3', 21),
    ('明天上午我会负责交接这部分工作。', 'Míngtiān shàngwǔ wǒ huì fùzé jiāojiē zhè bùfen gōngzuò.', 'Sáng mai tôi sẽ chịu trách nhiệm bàn giao phần công việc này.', '[{"chinese":"负责","pinyin":"fùzé","meaning_vi":"chịu trách nhiệm"},{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5c5e67ed036cdd96ea223e23.mp3', 22),
    ('请确认所有文件已经备份保存。', 'Qǐng quèrèn suǒyǒu wénjiàn yǐjīng bèifèn bǎocún.', 'Xin xác nhận tất cả tài liệu đã được sao lưu và lưu giữ.', '[{"chinese":"备份","pinyin":"bèifèn","meaning_vi":"sao lưu"},{"chinese":"保存","pinyin":"bǎocún","meaning_vi":"lưu giữ, bảo quản"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-20e444efd6ff4cca5935751f.mp3', 23),
    ('下午四点我们有一个电话会议，请准时参加。', 'Xiàwǔ sì diǎn wǒmen yǒu yí ge diànhuà huìyì, qǐng zhǔnshí cānjiā.', '4 giờ chiều chúng ta có một cuộc họp qua điện thoại, xin tham dự đúng giờ.', '[{"chinese":"电话会议","pinyin":"diànhuà huìyì","meaning_vi":"họp qua điện thoại"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-0c4edfd48c2b2c3eac037eb0.mp3', 24),
    ('早上好，请问今天的日程安排有什么变化吗？', 'Zǎoshang hǎo, qǐngwèn jīntiān de rìchéng ānpái yǒu shénme biànhuà ma?', 'Chào buổi sáng, xin hỏi lịch trình hôm nay có thay đổi gì không?', '[{"chinese":"日程安排","pinyin":"rìchéng ānpái","meaning_vi":"lịch trình, sắp xếp công việc"},{"chinese":"变化","pinyin":"biànhuà","meaning_vi":"thay đổi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f0c27f4e61f342ac810eb582.mp3', 25),
    ('请你负责这个项目的初步方案制定。', 'Qǐng nǐ fùzé zhège xiàngmù de chūbù fāng''àn zhìdìng.', 'Xin bạn chịu trách nhiệm xây dựng phương án sơ bộ cho dự án này.', '[{"chinese":"负责","pinyin":"fùzé","meaning_vi":"chịu trách nhiệm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e0579c37b0fcd9a8fef84a58.mp3', 26),
    ('我们需要明确任务的范围和具体要求。', 'Wǒmen xūyào míngquè rènwù de fànwéi hé jùtǐ yāoqiú.', 'Chúng ta cần làm rõ phạm vi và yêu cầu cụ thể của nhiệm vụ.', '[{"chinese":"范围","pinyin":"fànwéi","meaning_vi":"phạm vi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-fb629814333eddc843f39ed0.mp3', 27),
    ('请在本周内完成此任务，时间比较紧迫。', 'Qǐng zài běn zhōu nèi wánchéng cǐ rènwù, shíjiān bǐjiào jǐnpò.', 'Xin hoàn thành nhiệm vụ này trong tuần này, thời gian khá gấp.', '[{"chinese":"紧迫","pinyin":"jǐnpò","meaning_vi":"gấp gáp, cấp bách"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-eb96e30efb570be1d7acd381.mp3', 28),
    ('为了保证质量，请合理分配每个人的工作量。', 'Wèile bǎozhèng zhìliàng, qǐng hélǐ fēnpèi měi gèrén de gōngzuòliàng.', 'Để đảm bảo chất lượng, xin phân chia hợp lý khối lượng công việc của từng người.', '[{"chinese":"分配","pinyin":"fēnpèi","meaning_vi":"phân phối, phân chia"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-3163018eaf8cddea5565a280.mp3', 29),
    ('我们需要尽快调整项目的时间安排。', 'Wǒmen xūyào jǐnkuài tiáozhěng xiàngmù de shíjiān ānpái.', 'Chúng ta cần nhanh chóng điều chỉnh kế hoạch thời gian dự án.', '[{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8ea848cffaa53537fe76d7d9.mp3', 30),
    ('在会议上确认了任务的具体优先级。', 'Zài huìyì shàng quèrènle rènwù de jùtǐ yōuxiān jí.', 'Tại cuộc họp đã xác nhận rõ mức độ ưu tiên của nhiệm vụ.', '[{"chinese":"优先级","pinyin":"yōuxiānjí","meaning_vi":"độ ưu tiên"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-6ea62cb111231df9c1b99b9e.mp3', 31),
    ('请估算一下完成这项工作的所需时间。', 'Qǐng gūsuàn yīxià wánchéng zhè xiàng gōngzuò de suǒxū shíjiān.', 'Xin hãy ước lượng thời gian cần thiết để hoàn thành công việc này.', '[{"chinese":"所需时间","pinyin":"suǒxū shíjiān","meaning_vi":"thời gian cần thiết"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-29d2dbc821c16efa487b2606.mp3', 32),
    ('如果需要，我们可以延长任务的截止日期。', 'Rúguǒ xūyào, wǒmen kěyǐ yáncháng rènwù de jiézhǐ rìqī.', 'Nếu cần, chúng ta có thể gia hạn thời hạn hoàn thành nhiệm vụ.', '[{"chinese":"延长","pinyin":"yáncháng","meaning_vi":"gia hạn, kéo dài"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-69b3059b1926db744d16450d.mp3', 33),
    ('请先拆分任务，确保每个人都有明确职责。', 'Qǐng xiān chāifēn rènwù, quèbǎo měi gèrén dōu yǒu míngquè zhízé.', 'Xin hãy chia nhỏ nhiệm vụ trước, đảm bảo mỗi người đều có trách nhiệm rõ ràng.', '[{"chinese":"拆分","pinyin":"chāifēn","meaning_vi":"chia nhỏ, tách ra"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-0eb97387b1c25c8195a0fd5f.mp3', 34),
    ('针对这个项目，我们需要制定详细的计划。', 'Zhēnduì zhège xiàngmù, wǒmen xūyào zhìdìng xiángxì de jìhuà.', 'Đối với dự án này, chúng ta cần lập kế hoạch chi tiết.', '[{"chinese":"计划","pinyin":"jìhuà","meaning_vi":"kế hoạch"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c4b24186c12701b78923bb1d.mp3', 35),
    ('请确认所有任务范围内的工作内容。', 'Qǐng quèrèn suǒyǒu rènwù fànwéi nèi de gōngzuò nèiróng.', 'Xin xác nhận toàn bộ nội dung công việc trong phạm vi nhiệm vụ.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"范围","pinyin":"fànwéi","meaning_vi":"phạm vi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-56bb663112a550f1971ac05f.mp3', 36),
    ('请告知是否需要更多时间来完成工作。', 'Qǐng gàozhī shìfǒu xūyào gèng duō shíjiān lái wánchéng gōngzuò.', 'Xin cho biết có cần thêm thời gian để hoàn thành công việc không.', '[{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c3d1caa161a2ff9fe931ec4b.mp3', 37),
    ('项目负责人需及时汇报任务进展情况。', 'Xiàngmù fùzé rén xū jíshí huìbào rènwù jìnzhǎn qíngkuàng.', 'Người phụ trách dự án cần báo cáo tiến độ nhiệm vụ kịp thời.', '[{"chinese":"负责人","pinyin":"fùzé rén","meaning_vi":"người chịu trách nhiệm"},{"chinese":"汇报","pinyin":"huìbào","meaning_vi":"báo cáo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e2fa423e499e9cb821c71da8.mp3', 38),
    ('请在指定时间内优先完成重要任务。', 'Qǐng zài zhǐdìng shíjiān nèi yōuxiān wánchéng zhòngyào rènwù.', 'Xin ưu tiên hoàn thành nhiệm vụ quan trọng trong thời gian quy định.', '[{"chinese":"优先","pinyin":"yōuxiān","meaning_vi":"ưu tiên"},{"chinese":"指定","pinyin":"zhǐdìng","meaning_vi":"chỉ định"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-6c2ad5961eb30a4f0107ab4b.mp3', 39),
    ('我需要了解这项工作的具体要求。', 'Wǒ xūyào liǎojiě zhè xiàng gōngzuò de jùtǐ yāoqiú.', 'Tôi cần hiểu rõ yêu cầu cụ thể của công việc này.', '[{"chinese":"要求","pinyin":"yāoqiú","meaning_vi":"yêu cầu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-9fc8e074c47a8fb54c10a174.mp3', 40),
    ('分工明确可以提高团队的工作效率。', 'Fēngōng míngquè kěyǐ tígāo tuánduì de gōngzuò xiàolǜ.', 'Phân công rõ ràng có thể nâng cao hiệu quả làm việc của đội nhóm.', '[{"chinese":"分工","pinyin":"fēngōng","meaning_vi":"phân công"},{"chinese":"效率","pinyin":"xiàolǜ","meaning_vi":"hiệu suất, hiệu quả"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f1730943be82d087b70c48c0.mp3', 41),
    ('根据任务复杂度进行合理安排工作顺序。', 'Gēnjù rènwù fùzá dù jìnxíng hélǐ ānpái gōngzuò shùnxù.', 'Theo độ phức tạp của nhiệm vụ để sắp xếp thứ tự công việc hợp lý.', '[{"chinese":"复杂度","pinyin":"fùzá dù","meaning_vi":"độ phức tạp"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-1494e58ce6c7047a85df7624.mp3', 42),
    ('需要您确认项目的完成时限和质量标准。', 'Xūyào nín quèrèn xiàngmù de wánchéng shíxiàn hé zhìliàng biāozhǔn.', 'Cần bạn xác nhận thời hạn hoàn thành và tiêu chuẩn chất lượng của dự án.', '[{"chinese":"时限","pinyin":"shíxiàn","meaning_vi":"thời hạn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-251cf451f061744fb3093f8a.mp3', 43),
    ('请在截止日期前提交工作进度报告。', 'Qǐng zài jiézhǐ rìqī qián tíjiāo gōngzuò jìndù bàogào.', 'Vui lòng nộp báo cáo tiến độ công việc trước hạn chót.', '[{"chinese":"截止日期","pinyin":"jiézhǐ rìqī","meaning_vi":"hạn chót, ngày kết thúc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-35c7fb4794fb594ce7679868.mp3', 44),
    ('任务紧急，请优先处理并及时反馈结果。', 'Rènwù jǐnjí, qǐng yōuxiān chǔlǐ bìng jíshí fǎnkuì jiéguǒ.', 'Nhiệm vụ cấp bách, vui lòng ưu tiên xử lý và phản hồi kết quả kịp thời.', '[{"chinese":"紧急","pinyin":"jǐnjí","meaning_vi":"cấp bách"},{"chinese":"处理","pinyin":"chǔlǐ","meaning_vi":"xử lý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-291000b3ac369442dbbf7eb5.mp3', 45),
    ('请按照计划合理安排每天的工作任务。', 'Qǐng ànzhào jìhuà hélǐ ānpái měitiān de gōngzuò rènwù.', 'Xin theo kế hoạch để sắp xếp hợp lý nhiệm vụ công việc hàng ngày.', '[{"chinese":"合理","pinyin":"hélǐ","meaning_vi":"hợp lý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-be500de13a4dd4b08b938c9a.mp3', 46),
    ('这项工作的负责人已经确定，请直接联系他。', 'Zhè xiàng gōngzuò de fùzé rén yǐjīng quèdìng, qǐng zhíjiē liánxì tā.', 'Người chịu trách nhiệm công việc này đã được xác định, vui lòng liên hệ trực tiếp.', '[{"chinese":"负责人","pinyin":"fùzé rén","meaning_vi":"người chịu trách nhiệm"},{"chinese":"确定","pinyin":"quèdìng","meaning_vi":"xác định"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c1b3337cf6d52896462b8c2a.mp3', 47),
    ('请提前告知如果任务有什么变化需要调整。', 'Qǐng tíqián gàozhī rúguǒ rènwù yǒu shé me biànhuà xūyào tiáozhěng.', 'Xin báo trước nếu nhiệm vụ có bất kỳ thay đổi nào cần điều chỉnh.', '[{"chinese":"提前","pinyin":"tíqián","meaning_vi":"trước, sớm"},{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-9749281d416d460161d2cf52.mp3', 48),
    ('工作量较大，建议合理分工并安排时间。', 'Gōngzuò liàng jiào dà, jiànyì hélǐ fēngōng bìng ānpái shíjiān.', 'Khối lượng công việc khá lớn, đề nghị phân công hợp lý và sắp xếp thời gian.', '[{"chinese":"分工","pinyin":"fēngōng","meaning_vi":"phân công"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8bd9d9202dc601019aa3f50b.mp3', 49),
    ('请确认是否所有相关人员都已收到任务通知。', 'Qǐng quèrèn shìfǒu suǒyǒu xiāngguān rényuán dōu yǐ shōu dào rènwù tōngzhī.', 'Xin xác nhận tất cả các nhân sự liên quan đã nhận được thông báo nhiệm vụ chưa.', '[{"chinese":"相关人员","pinyin":"xiāngguān rényuán","meaning_vi":"nhân sự liên quan"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-28e3680299fadfc844c24809.mp3', 50),
    ('目前项目进度稍有滞后，主要原因是供应链出现了延迟。', 'Mùqián xiàngmù jìndù shāoyǒu zhìhòu, zhǔyào yuányīn shì gōngyìngliàn chūxiànle yánchí.', 'Hiện tại tiến độ dự án hơi chậm trễ, nguyên nhân chính là chuỗi cung ứng bị trì hoãn.', '[{"chinese":"滞后","pinyin":"zhìhòu","meaning_vi":"chậm trễ, lùi lại"},{"chinese":"延迟","pinyin":"yánchí","meaning_vi":"trì hoãn, chậm trễ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-70c21441751b530bbe34c5c0.mp3', 51),
    ('我已经完成了初步设计，现在正在进行细节的优化工作。', 'Wǒ yǐjīng wánchéngle chūbù shèjì, xiànzài zhèngzài jìnxíng xìjié de yōuhuà gōngzuò.', 'Tôi đã hoàn thành thiết kế sơ bộ, hiện đang tiến hành công việc tối ưu các chi tiết.', '[{"chinese":"优化","pinyin":"yōuhuà","meaning_vi":"tối ưu, cải tiến"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-048cef32675fac4d22cbaaf4.mp3', 52),
    ('系统测试中发现了几个关键性的漏洞，需立即进行修复。', 'Xìtǒng cèshì zhōng fāxiànle jǐ gè guānjiàn xìng de lòudòng, xū lìjí jìnxíng xiūfù.', 'Đang trong quá trình kiểm tra hệ thống phát hiện vài lỗ hổng quan trọng, cần phải sửa chữa ngay lập tức.', '[{"chinese":"关键性","pinyin":"guānjiàn xìng","meaning_vi":"tính then chốt, quan trọng"},{"chinese":"修复","pinyin":"xiūfù","meaning_vi":"sửa chữa, khôi phục"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5c6fef63c496cf6e5b31a096.mp3', 53),
    ('由于团队成员缺乏经验，导致任务进展出现了瓶颈。', 'Yóuyú tuánduì chéngyuán quēfá jīngyàn, dǎozhì rènwù jìnzhǎn chūxiànle píngjǐng.', 'Do các thành viên trong nhóm còn thiếu kinh nghiệm nên tiến độ công việc gặp điểm nghẽn.', '[{"chinese":"瓶颈","pinyin":"píngjǐng","meaning_vi":"thắt nút, điểm nghẽn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-47bef892366d7f703fe24776.mp3', 54),
    ('请您审核最新的进度报告，确认信息是否准确无误。', 'Qǐng nín shěnhé zuìxīn de jìndù bàogào, quèrèn xìnxī shìfǒu zhǔnquè wúwù.', 'Mong bạn duyệt báo cáo tiến độ mới nhất, xác nhận thông tin có chính xác hay không.', '[{"chinese":"审核","pinyin":"shěnhé","meaning_vi":"duyệt xét, kiểm tra"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f7f90c48b769ae1e7e55c936.mp3', 55),
    ('项目存在一定的风险，我们需要制定相应的应对措施。', 'Xiàngmù cúnzài yídìng de fēngxiǎn, wǒmen xūyào zhìdìng xiāngyìng de yìngduì cuòshī.', 'Dự án tồn tại một số rủi ro, chúng ta cần xây dựng các biện pháp ứng phó phù hợp.', '[{"chinese":"风险","pinyin":"fēngxiǎn","meaning_vi":"rủi ro"},{"chinese":"应对措施","pinyin":"yìngduì cuòshī","meaning_vi":"biện pháp ứng phó"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-91268b8797e0eb520d915056.mp3', 56),
    ('遇到问题请及时反馈，以便我们能迅速调整方案。', 'Yù dào wèntí qǐng jíshí fǎnkuì, yǐbiàn wǒmen néng xùnsù tiáozhěng fāng''àn.', 'Gặp vấn đề hãy phản hồi kịp thời để chúng tôi có thể nhanh chóng điều chỉnh phương án.', '[{"chinese":"方案","pinyin":"fāng''àn","meaning_vi":"phương án, kế hoạch"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d77b83ce090b6221a07751b7.mp3', 57),
    ('目前我们正在解决软件开发中的几个关键缺陷。', 'Mùqián wǒmen zhèngzài jiějué ruǎnjiàn kāifā zhōng de jǐ gè guānjiàn quēxiàn.', 'Hiện tại chúng tôi đang xử lý một số lỗi quan trọng trong phần mềm.', '[{"chinese":"关键缺陷","pinyin":"guānjiàn quēxiàn","meaning_vi":"lỗi quan trọng, khiếm khuyết nghiêm trọng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2e1bf9c276403cbe4a8f8571.mp3', 58),
    ('我们预计下周可以完成剩余的测试任务。', 'Wǒmen yùjì xià zhōu kěyǐ wánchéng shèngyú de cèshì rènwù.', 'Chúng tôi dự đoán tuần tới có thể hoàn thành phần nhiệm vụ kiểm thử còn lại.', '[{"chinese":"预计","pinyin":"yùjì","meaning_vi":"dự đoán, dự kiến"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-bf6b5a29e8a81a983ead823f.mp3', 59),
    ('为避免类似问题再次发生，我们已经加强了质量监控。', 'Wèi bìmiǎn lèisì wèntí zài cì fāshēng, wǒmen yǐjīng jiāqiángle zhìliàng jiānkòng.', 'Để tránh vấn đề tương tự tái phát, chúng tôi đã tăng cường giám sát chất lượng.', '[{"chinese":"监控","pinyin":"jiānkòng","meaning_vi":"giám sát"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-703cd5465292e85c2cfdaedc.mp3', 60),
    ('请协调相关部门协助解决目前存在的问题。', 'Qǐng xiétiáo xiāngguān bùmén xiézhù jiějué mùqián cúnzài de wèntí.', 'Xin phối hợp các phòng ban liên quan hỗ trợ giải quyết các vấn đề hiện tại.', '[{"chinese":"协调","pinyin":"xiétiáo","meaning_vi":"phối hợp, điều phối"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-7cdafe8dbd86b217f0496531.mp3', 61),
    ('工作计划已提交，请尽快确认并提出修改建议。', 'Gōngzuò jìhuà yǐ tíjiāo, qǐng jǐnkuài quèrèn bìng tíchū xiūgǎi jiànyì.', 'Kế hoạch công việc đã nộp, xin xác nhận sớm và đưa ra đề xuất chỉnh sửa.', '[{"chinese":"提交","pinyin":"tíjiāo","meaning_vi":"nộp, gửi"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"修改","pinyin":"xiūgǎi","meaning_vi":"sửa đổi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d37f39c2306510d99310a43c.mp3', 62),
    ('当前进展顺利，没有发现任何新的障碍。', 'Dāngqián jìnzhǎn shùnlì, méiyǒu fāxiàn rènhé xīn de zhàng''ài.', 'Tiến triển hiện tại thuận lợi, không phát hiện bất kỳ trở ngại mới nào.', '[{"chinese":"障碍","pinyin":"zhàng''ài","meaning_vi":"trở ngại, chướng ngại"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-bc8aadf243f7419af48a8bf5.mp3', 63),
    ('由于需求变更，项目时间表需要重新调整。', 'Yóuyú xūqiú biàngēng, xiàngmù shíjiān biǎo xūyào chóngxīn tiáozhěng.', 'Do yêu cầu thay đổi, lịch trình dự án cần được điều chỉnh lại.', '[{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-dafa0f6f3c85ea7ec06f9080.mp3', 64),
    ('请确认是否需要额外资源支持当前工作。', 'Qǐng quèrèn shìfǒu xūyào éwài zīyuán zhīchí dāngqián gōngzuò.', 'Xin xác nhận liệu có cần thêm nguồn lực hỗ trợ công việc hiện tại không.', '[{"chinese":"资源","pinyin":"zīyuán","meaning_vi":"nguồn lực, tài nguyên"},{"chinese":"支持","pinyin":"zhīchí","meaning_vi":"hỗ trợ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-52bda487360657999c2ece45.mp3', 65),
    ('系统已恢复正常，但仍需要继续观察其稳定性。', 'Xìtǒng yǐ huīfù zhèngcháng, dàn réng xūyào jìxù guānchá qí wěndìngxìng.', 'Hệ thống đã trở lại bình thường, nhưng vẫn cần tiếp tục theo dõi độ ổn định của nó.', '[{"chinese":"稳定性","pinyin":"wěndìngxìng","meaning_vi":"tính ổn định"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-fc60a93a74133b7d9be58450.mp3', 66),
    ('为了确保进度，请各部门按时提交阶段性报告。', 'Wèile quèbǎo jìndù, qǐng gè bùmén ànshí tíjiāo jiēduàn xìng bàogào.', 'Để đảm bảo tiến độ, xin các phòng ban nộp báo cáo từng giai đoạn đúng hạn.', '[{"chinese":"阶段性","pinyin":"jiēduàn xìng","meaning_vi":"tính giai đoạn, từng giai đoạn"},{"chinese":"确保","pinyin":"quèbǎo","meaning_vi":"đảm bảo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d90d0dd933634a38770cc111.mp3', 67),
    ('由于技术难题，预计项目完工日期将有所延长。', 'Yóuyú jìshù nántí, yùjì xiàngmù wángōng rìqī jiāng yǒu suǒ yáncháng.', 'Do khó khăn kỹ thuật, dự kiến ngày hoàn thành dự án sẽ bị trì hoãn một chút.', '[{"chinese":"延长","pinyin":"yáncháng","meaning_vi":"kéo dài, hoãn lại"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-a0856011064c1e0629e5a938.mp3', 68),
    ('项目组需要协调沟通，避免信息传递出现误差。', 'Xiàngmù zǔ xūyào xiétiáo gōutōng, bìmiǎn xìnxī chuándì chūxiàn wùchā.', 'Đội dự án cần phối hợp giao tiếp, tránh xuất hiện sai sót trong truyền đạt thông tin.', '[{"chinese":"误差","pinyin":"wùchā","meaning_vi":"sai số, sai sót"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-7608dd82010fe4468206711e.mp3', 69),
    ('请尽快完成提交，避免影响后续的流程安排。', 'Qǐng jǐnkuài wánchéng tíjiāo, bìmiǎn yǐngxiǎng hòuxù de liúchéng ānpái.', 'Xin nhanh chóng hoàn thành nộp hồ sơ để không ảnh hưởng tới những bước tiếp theo trong quy trình.', '[{"chinese":"流程","pinyin":"liúchéng","meaning_vi":"quy trình"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d678d3bc4bac2f269b2da179.mp3', 70),
    ('针对发现的问题，我们已经制定了详细的解决策略。', 'Zhēnduì fāxiàn de wèntí, wǒmen yǐjīng zhìdìngle xiángxì de jiějué cèlüè.', 'Đối với những vấn đề phát hiện được, chúng ta đã xây dựng chiến lược giải quyết chi tiết.', '[{"chinese":"策略","pinyin":"cèlüè","meaning_vi":"chiến lược, sách lược"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-ca4db2a07569b888918f7dc1.mp3', 71),
    ('今天的工作已全部完成，明天将开始新阶段的准备工作。', 'Jīntiān de gōngzuò yǐ quánbù wánchéng, míngtiān jiāng kāishǐ xīn jiēduàn de zhǔnbèi gōngzuò.', 'Công việc hôm nay đã hoàn tất, ngày mai sẽ bắt đầu chuẩn bị cho giai đoạn mới.', '[{"chinese":"全部","pinyin":"quánbù","meaning_vi":"toàn bộ"},{"chinese":"阶段","pinyin":"jiēduàn","meaning_vi":"giai đoạn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-32d684dd6dc9a958c5323342.mp3', 72),
    ('由于资源不足，项目推进速度受到一定限制。', 'Yóuyú zīyuán bùzú, xiàngmù tuījìn sùdù shòudào yídìng xiànzhì.', 'Do nguồn lực không đủ, tốc độ triển khai dự án bị giới hạn một phần.', '[{"chinese":"资源","pinyin":"zīyuán","meaning_vi":"nguồn lực, tài nguyên"},{"chinese":"限制","pinyin":"xiànzhì","meaning_vi":"giới hạn, hạn chế"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-742e13e71c977e798be756e6.mp3', 73),
    ('请注意风险点，及时采取预防措施减少损失。', 'Qǐng zhùyì fēngxiǎn diǎn, jíshí cǎiqǔ yùfáng cuòshī jiǎnshǎo sǔnshī.', 'Xin chú ý những điểm rủi ro, kịp thời áp dụng biện pháp phòng ngừa để giảm thiểu thiệt hại.', '[{"chinese":"风险点","pinyin":"fēngxiǎn diǎn","meaning_vi":"điểm rủi ro"},{"chinese":"预防措施","pinyin":"yùfáng cuòshī","meaning_vi":"biện pháp phòng ngừa"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-86baf8fc5f017d668b65fe74.mp3', 74),
    ('请大家随时报告工作中遇到的任何问题或异常情况。', 'Qǐng dàjiā suíshí bàogào gōngzuò zhōng yù dào de rènhé wèntí huò yìcháng qíngkuàng.', 'Mong mọi người báo cáo kịp thời bất kỳ vấn đề hoặc tình trạng bất thường nào gặp phải trong công việc.', '[{"chinese":"异常情况","pinyin":"yìcháng qíngkuàng","meaning_vi":"tình trạng bất thường"},{"chinese":"报告","pinyin":"bàogào","meaning_vi":"báo cáo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-dd8a93a2880b3fc419cac798.mp3', 75),
    ('请各位同事确认一下下周会议的时间安排。', 'Qǐng gèwèi tóngshì quèrèn yīxià xià zhōu huìyì de shíjiān ānpái.', 'Mời các đồng nghiệp xác nhận lịch họp tuần tới.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"会议","pinyin":"huìyì","meaning_vi":"cuộc họp"},{"chinese":"时间安排","pinyin":"shíjiān ānpái","meaning_vi":"sắp xếp thời gian"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8a7f6697d2681534e0f42363.mp3', 76),
    ('由于议程调整，会议时间改为下午三点开始。', 'Yóuyú yìchéng tiáozhěng, huìyì shíjiān gǎi wèi xiàwǔ sān diǎn kāishǐ.', 'Do điều chỉnh chương trình, thời gian họp đổi thành 3 giờ chiều bắt đầu.', '[{"chinese":"议程调整","pinyin":"yìchéng tiáozhěng","meaning_vi":"điều chỉnh chương trình"},{"chinese":"会议时间","pinyin":"huìyì shíjiān","meaning_vi":"thời gian họp"},{"chinese":"改为","pinyin":"gǎi wèi","meaning_vi":"đổi thành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-3c03c4f76c406d3eaca89954.mp3', 77),
    ('今天的会议议程包括项目进展和预算审核。', 'Jīntiān de huìyì yìchéng bāokuò xiàngmù jìnzhǎn hé yùsuàn shěnhé.', 'Chương trình họp hôm nay gồm tiến độ dự án và phần xét duyệt ngân sách.', '[{"chinese":"会议议程","pinyin":"huìyì yìchéng","meaning_vi":"chương trình, nội dung cuộc họp"},{"chinese":"项目进展","pinyin":"xiàngmù jìnzhǎn","meaning_vi":"tiến độ dự án"},{"chinese":"预算审核","pinyin":"yùsuàn shěnhé","meaning_vi":"xét duyệt ngân sách"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c87e4df25046a20a2baaf3d6.mp3', 78),
    ('现在开始介绍本季度的销售业绩，请大家注意。', 'Xiànzài kāishǐ jièshào běn jìdù de xiāoshòu yèjì, qǐng dàjiā zhùyì.', 'Bây giờ bắt đầu trình bày doanh số quý này, mọi người chú ý nhé.', '[{"chinese":"介绍","pinyin":"jièshào","meaning_vi":"giới thiệu, trình bày"},{"chinese":"季度","pinyin":"jìdù","meaning_vi":"quý (thời gian)"},{"chinese":"销售业绩","pinyin":"xiāoshòu yèjì","meaning_vi":"doanh số bán hàng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-bceb0bcdbd9da259b46c45a7.mp3', 79),
    ('对于新项目，我有一些不同的看法想和大家分享。', 'Duìyú xīn xiàngmù, wǒ yǒu yīxiē bùtóng de kànfǎ xiǎng hé dàjiā fēnxiǎng.', 'Về dự án mới, tôi có vài ý kiến khác muốn chia sẻ với mọi người.', '[{"chinese":"新项目","pinyin":"xīn xiàngmù","meaning_vi":"dự án mới"},{"chinese":"不同的看法","pinyin":"bùtóng de kànfǎ","meaning_vi":"quan điểm khác nhau"},{"chinese":"分享","pinyin":"fēnxiǎng","meaning_vi":"chia sẻ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-0c4908903409da71345f5d65.mp3', 80),
    ('请问在预算方面是否还有进一步的调整意见？', 'Qǐngwèn zài yùsuàn fāngmiàn shìfǒu hái yǒu jìnyībù de tiáozhěng yìjiàn?', 'Xin hỏi về ngân sách liệu còn ý kiến điều chỉnh nào thêm không?', '[{"chinese":"预算方面","pinyin":"yùsuàn fāngmiàn","meaning_vi":"về mặt ngân sách"},{"chinese":"进一步","pinyin":"jìnyībù","meaning_vi":"hơn nữa, thêm"},{"chinese":"调整意见","pinyin":"tiáozhěng yìjiàn","meaning_vi":"ý kiến điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f1536a3c976ca3f16ee00192.mp3', 81),
    ('我完全同意您的建议，认为这是目前最佳方案。', 'Wǒ wánquán tóngyì nín de jiànyì, rènwéi zhè shì mùqián zuì jiā fāng''àn.', 'Tôi hoàn toàn đồng ý với đề xuất của anh/chị, cho rằng đây là phương án tốt nhất hiện tại.', '[{"chinese":"完全同意","pinyin":"wánquán tóngyì","meaning_vi":"hoàn toàn đồng ý"},{"chinese":"建议","pinyin":"jiànyì","meaning_vi":"đề xuất, khuyến nghị"},{"chinese":"最佳方案","pinyin":"zuì jiā fāng''àn","meaning_vi":"phương án tốt nhất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-132bd31e7609ee8650e80a1e.mp3', 82),
    ('关于预算问题，大家有其他不同的看法吗？', 'Guānyú yùsuàn wèntí, dàjiā yǒu qítā bùtóng de kànfǎ ma?', 'Về vấn đề ngân sách, mọi người có ý kiến khác nào không?', '[{"chinese":"预算问题","pinyin":"yùsuàn wèntí","meaning_vi":"vấn đề ngân sách"},{"chinese":"其他","pinyin":"qítā","meaning_vi":"khác"},{"chinese":"看法","pinyin":"kànfǎ","meaning_vi":"quan điểm, ý kiến"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e55f01ac46806be8ff2c293a.mp3', 83),
    ('经过讨论，我们决定将项目延期一个月。', 'Jīngguò tǎolùn, wǒmen juédìng jiāng xiàngmù yánqī yīgè yuè.', 'Sau khi thảo luận, chúng tôi quyết định hoãn dự án thêm một tháng.', '[{"chinese":"经过讨论","pinyin":"jīngguò tǎolùn","meaning_vi":"sau khi thảo luận"},{"chinese":"决定","pinyin":"juédìng","meaning_vi":"quyết định"},{"chinese":"延期","pinyin":"yánqī","meaning_vi":"hoãn, kéo dài thêm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-fffe0a27c7508944b4c71b3b.mp3', 84),
    ('请记录员在会议结束后整理会议纪要。', 'Qǐng jìlùyuán zài huìyì jiéshù hòu zhěnglǐ huìyì jìyào.', 'Sau cuộc họp, vui lòng nhờ người ghi biên bản tổng hợp nội dung cuộc họp.', '[{"chinese":"记录员","pinyin":"jìlùyuán","meaning_vi":"người ghi biên bản"},{"chinese":"整理","pinyin":"zhěnglǐ","meaning_vi":"sắp xếp, tổng hợp"},{"chinese":"会议纪要","pinyin":"huìyì jìyào","meaning_vi":"biên bản cuộc họp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-a19588ea7d3f20ad60d70225.mp3', 85),
    ('会后我会把任务分配表发送给相关人员。', 'Huì hòu wǒ huì bǎ rènwu fēnpèi biǎo fāsòng gěi xiāngguān rényuán.', 'Sau họp, tôi sẽ gửi bảng phân công nhiệm vụ cho các nhân sự liên quan.', '[{"chinese":"会后","pinyin":"huì hòu","meaning_vi":"sau họp"},{"chinese":"任务分配表","pinyin":"rènwu fēnpèi biǎo","meaning_vi":"bảng phân công nhiệm vụ"},{"chinese":"相关人员","pinyin":"xiāngguān rényuán","meaning_vi":"người liên quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8ac043f80db27b12582e9404.mp3', 86),
    ('请确认今天会议所做的决定是否准确无误。', 'Qǐng quèrèn jīntiān huìyì suǒzuò de juédìng shìfǒu zhǔnquè wúwù.', 'Xin xác nhận các quyết định trong cuộc họp hôm nay có chính xác không sai sót.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"决定","pinyin":"juédìng","meaning_vi":"quyết định"},{"chinese":"准确无误","pinyin":"zhǔnquè wúwù","meaning_vi":"chính xác, không sai sót"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-4bcac3e9df047f338c7c7406.mp3', 87),
    ('会议议题需要提前发送，以便成员做好准备。', 'Huìyì yìtí xūyào tíqián fāsòng, yǐbiàn chéngyuán zuò hǎo zhǔnbèi.', 'Chủ đề họp cần gửi trước để các thành viên chuẩn bị tốt.', '[{"chinese":"会议议题","pinyin":"huìyì yìtí","meaning_vi":"chủ đề cuộc họp"},{"chinese":"提前发送","pinyin":"tíqián fāsòng","meaning_vi":"gửi trước"},{"chinese":"做好准备","pinyin":"zuò hǎo zhǔnbèi","meaning_vi":"chuẩn bị tốt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8fd5262814a9d45ad2deb181.mp3', 88),
    ('请问大家对新的项目方案有什么疑问？', 'Qǐngwèn dàjiā duì xīn de xiàngmù fāng''àn yǒu shé me yíwèn?', 'Mọi người có thắc mắc gì về phương án dự án mới không?', '[{"chinese":"项目方案","pinyin":"xiàngmù fāng''àn","meaning_vi":"phương án dự án"},{"chinese":"有什么疑问","pinyin":"yǒu shé me yíwèn","meaning_vi":"có thắc mắc gì"},{"chinese":"请问","pinyin":"qǐngwèn","meaning_vi":"xin hỏi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-688bcdee82b9ea0fc603e223.mp3', 89),
    ('我同意这个计划，不过需要增加时间预算。', 'Wǒ tóngyì zhège jìhuà, bùguò xūyào zēngjiā shíjiān yùsuàn.', 'Tôi đồng ý kế hoạch này, nhưng cần tăng thêm dự toán thời gian.', '[{"chinese":"同意","pinyin":"tóngyì","meaning_vi":"đồng ý"},{"chinese":"计划","pinyin":"jìhuà","meaning_vi":"kế hoạch"},{"chinese":"时间预算","pinyin":"shíjiān yùsuàn","meaning_vi":"dự toán thời gian"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-290b0c67d9b2bb9b6f754a50.mp3', 90),
    ('总结今天会议，我们达成了几个重要共识。', 'Zǒngjié jīntiān huìyì, wǒmen dáchéng le jǐ gè zhòngyào gòngshí.', 'Tổng kết cuộc họp hôm nay, chúng ta đã đạt được một số đồng thuận quan trọng.', '[{"chinese":"总结","pinyin":"zǒngjié","meaning_vi":"tổng kết"},{"chinese":"达成","pinyin":"dáchéng","meaning_vi":"đạt được"},{"chinese":"共识","pinyin":"gòngshí","meaning_vi":"nhận thức chung"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8ef1b5f7c744528c0b86e5bf.mp3', 91),
    ('请确认已经记录好每位发言者的观点。', 'Qǐng quèrèn yǐjīng jìlù hǎo měi wèi fāyán zhě de guāndiǎn.', 'Xin hãy xác nhận đã ghi lại đầy đủ quan điểm của từng người phát biểu.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"记录","pinyin":"jìlù","meaning_vi":"ghi chép"},{"chinese":"观点","pinyin":"guāndiǎn","meaning_vi":"quan điểm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-db005a7b982ca8834fec8a5d.mp3', 92),
    ('根据会议决定，下一步由市场部门负责跟进。', 'Gēnjù huìyì juédìng, xià yībù yóu shìchǎng bùmén fùzé gēnjìn.', 'Theo quyết định họp, bước tiếp theo do phòng thị trường phụ trách theo dõi.', '[{"chinese":"根据","pinyin":"gēnjù","meaning_vi":"dựa theo"},{"chinese":"会议决定","pinyin":"huìyì juédìng","meaning_vi":"quyết định cuộc họp"},{"chinese":"负责跟进","pinyin":"fùzé gēnjìn","meaning_vi":"phụ trách theo dõi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-ed9d3b8c6c970bfabb1c6a99.mp3', 93),
    ('请大家准时参加明天上午的部门例会。', 'Qǐng dàjiā zhǔnshí cānjiā míngtiān shàngwǔ de bùmén lì huì.', 'Mọi người vui lòng tham dự họp định kỳ phòng ban sáng mai đúng giờ.', '[{"chinese":"准时","pinyin":"zhǔnshí","meaning_vi":"đúng giờ"},{"chinese":"部门例会","pinyin":"bùmén lì huì","meaning_vi":"họp định kỳ phòng ban"},{"chinese":"参加","pinyin":"cānjiā","meaning_vi":"tham gia, tham dự"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-774c71be4f3e117b3cc2970f.mp3', 94),
    ('会议结束后，请大家及时反馈工作进展情况。', 'Huìyì jiéshù hòu, qǐng dàjiā jíshí fǎnkuì gōngzuò jìnzhǎn qíngkuàng.', 'Sau khi kết thúc họp, xin mọi người kịp thời phản hồi tình hình tiến độ công việc.', '[{"chinese":"会议结束","pinyin":"huìyì jiéshù","meaning_vi":"kết thúc cuộc họp"},{"chinese":"及时反馈","pinyin":"jíshí fǎnkuì","meaning_vi":"phản hồi kịp thời"},{"chinese":"工作进展情况","pinyin":"gōngzuò jìnzhǎn qíngkuàng","meaning_vi":"tình hình tiến độ công việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-651123aa6ac705f35485d9cb.mp3', 95),
    ('我们需要明确分工，确保各自职责清晰。', 'Wǒmen xūyào míngquè fēngōng, quèbǎo gèzì zhízé qīngxī.', 'Chúng ta cần phân công rõ ràng, đảm bảo trách nhiệm từng người rõ ràng.', '[{"chinese":"明确分工","pinyin":"míngquè fēngōng","meaning_vi":"phân công rõ ràng"},{"chinese":"确保","pinyin":"quèbǎo","meaning_vi":"đảm bảo"},{"chinese":"职责清晰","pinyin":"zhízé qīngxī","meaning_vi":"trách nhiệm rõ ràng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-a15ad40fc56fccf0c5099e54.mp3', 96),
    ('这次会议我们重点讨论了下一步的执行方案。', 'Zhè cì huìyì wǒmen zhòngdiǎn tǎolùn le xià yībù de zhíxíng fāng''àn.', 'Cuộc họp này chúng ta tập trung thảo luận phương án thực thi tiếp theo.', '[{"chinese":"重点讨论","pinyin":"zhòngdiǎn tǎolùn","meaning_vi":"thảo luận trọng điểm"},{"chinese":"下一步","pinyin":"xià yībù","meaning_vi":"bước tiếp theo"},{"chinese":"执行方案","pinyin":"zhíxíng fāng''àn","meaning_vi":"phương án thực thi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5ebcb7666b35151270fe14ac.mp3', 97),
    ('请确认所有会议设备在使用前已经调试完毕。', 'Qǐng quèrèn suǒyǒu huìyì shèbèi zài shǐyòng qián yǐjīng tiáoshì wánbì.', 'Xin vui lòng xác nhận tất cả thiết bị họp đã được thử nghiệm trước khi sử dụng.', '[{"chinese":"会议设备","pinyin":"huìyì shèbèi","meaning_vi":"thiết bị họp"},{"chinese":"使用前","pinyin":"shǐyòng qián","meaning_vi":"trước khi sử dụng"},{"chinese":"调试完毕","pinyin":"tiáoshì wánbì","meaning_vi":"đã thử nghiệm hoàn tất"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-b1b4705d0d6f523362ee0ca0.mp3', 98),
    ('请大家在会议期间保持手机静音状态。', 'Qǐng dàjiā zài huìyì qījiān bǎochí shǒujī jìngyīn zhuàngtài.', 'Kính mong mọi người trong thời gian họp giữ điện thoại ở chế độ im lặng.', '[{"chinese":"会议期间","pinyin":"huìyì qījiān","meaning_vi":"trong thời gian họp"},{"chinese":"保持","pinyin":"bǎochí","meaning_vi":"giữ, duy trì"},{"chinese":"静音状态","pinyin":"jìngyīn zhuàngtài","meaning_vi":"chế độ im lặng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f5e41a3caf3b09eab3be5a16.mp3', 99),
    ('请将会议纪要整理后发送给所有参与同事。', 'Qǐng jiāng huìyì jìyào zhěnglǐ hòu fāsòng gěi suǒyǒu cānyù tóngshì.', 'Xin hãy tổng hợp biên bản họp rồi gửi cho tất cả đồng nghiệp tham gia.', '[{"chinese":"会议纪要","pinyin":"huìyì jìyào","meaning_vi":"biên bản họp"},{"chinese":"整理","pinyin":"zhěnglǐ","meaning_vi":"sắp xếp, tổng hợp"},{"chinese":"参与同事","pinyin":"cānyù tóngshì","meaning_vi":"đồng nghiệp tham gia"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2012f1741697f0dd7cf6d55f.mp3', 100),
    ('我今天因身体不适，申请一天的病假。', 'Wǒ jīntiān yīn shēntǐ bú shì, shēnqǐng yì tiān de bìngjià.', 'Hôm nay tôi sức khỏe không tốt, xin nghỉ ốm một ngày.', '[{"chinese":"身体不适","pinyin":"shēntǐ bú shì","meaning_vi":"sức khỏe không tốt"},{"chinese":"申请","pinyin":"shēnqǐng","meaning_vi":"xin, đăng ký"},{"chinese":"病假","pinyin":"bìngjià","meaning_vi":"nghỉ ốm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-bc91a20c2097b6c4223bf99c.mp3', 101),
    ('请假期间，我会安排同事代为处理工作交接。', 'Qǐngjià qījiān, wǒ huì ānpái tóngshì dàiwéi chǔlǐ gōngzuò jiāojiē.', 'Trong thời gian xin nghỉ, tôi sẽ sắp xếp đồng nghiệp thay xử lý bàn giao công việc.', '[{"chinese":"请假期间","pinyin":"qǐngjià qījiān","meaning_vi":"thời gian xin nghỉ"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"},{"chinese":"工作交接","pinyin":"gōngzuò jiāojiē","meaning_vi":"bàn giao công việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-00b1cc4f22af75e35794564e.mp3', 102),
    ('由于交通堵塞，我今天可能会迟到几分钟。', 'Yóuyú jiāotōng dǔsè, wǒ jīntiān kěnéng huì chídào jǐ fēnzhōng.', 'Do kẹt xe, hôm nay tôi có thể đến muộn vài phút.', '[{"chinese":"交通堵塞","pinyin":"jiāotōng dǔsè","meaning_vi":"kẹt xe"},{"chinese":"迟到","pinyin":"chídào","meaning_vi":"đi muộn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8eb988aefd37f7c9901fa771.mp3', 103),
    ('因为要接送孩子，我今天需要提前离开办公室。', 'Yīnwèi yào jiēsòng háizi, wǒ jīntiān xūyào tíqián líkāi bàngōngshì.', 'Vì phải đón con, hôm nay tôi cần về sớm khỏi văn phòng.', '[{"chinese":"提前离开","pinyin":"tíqián líkāi","meaning_vi":"rời đi sớm"},{"chinese":"接送","pinyin":"jiēsòng","meaning_vi":"đón đưa"},{"chinese":"办公室","pinyin":"bàngōngshì","meaning_vi":"văn phòng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-04106e970f6871dee6c15b1c.mp3', 104),
    ('今天晚上我需要加班完成项目的最后阶段任务。', 'Jīntiān wǎnshàng wǒ xūyào jiābān wánchéng xiàngmù de zuìhòu jiēduàn rènwu.', 'Tối nay tôi cần làm thêm giờ để hoàn thành nhiệm vụ giai đoạn cuối của dự án.', '[{"chinese":"加班","pinyin":"jiābān","meaning_vi":"làm thêm giờ"},{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"},{"chinese":"最后阶段","pinyin":"zuìhòu jiēduàn","meaning_vi":"giai đoạn cuối"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-e1448a69c4bf7f8f53ed91b5.mp3', 105),
    ('考虑到家庭情况，我打算下个月开始远程办公。', 'Kǎolǜ dào jiātíng qíngkuàng, wǒ dǎsuàn xià ge yuè kāishǐ yuǎnchéng bàngōng.', 'Xem xét tình hình gia đình, tôi dự định bắt đầu làm việc từ xa từ tháng tới.', '[{"chinese":"家庭情况","pinyin":"jiātíng qíngkuàng","meaning_vi":"tình hình gia đình"},{"chinese":"远程办公","pinyin":"yuǎnchéng bàngōng","meaning_vi":"làm việc từ xa"},{"chinese":"打算","pinyin":"dǎsuàn","meaning_vi":"dự định"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-72fa70fc83b7eac409093d22.mp3', 106),
    ('下周我要去外地出差，预计会工作一周。', 'Xià zhōu wǒ yào qù wàidì chūchāi, yùjì huì gōngzuò yī zhōu.', 'Tuần tới tôi sẽ đi công tác ngoài tỉnh, dự kiến làm việc một tuần.', '[{"chinese":"出差","pinyin":"chūchāi","meaning_vi":"đi công tác"},{"chinese":"预计","pinyin":"yùjì","meaning_vi":"dự kiến"},{"chinese":"外地","pinyin":"wàidì","meaning_vi":"ngoài tỉnh, nơi khác"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-b8cd803cbe07a2d96a7fae9e.mp3', 107),
    ('请提前通知我，如果需要我协助处理紧急事务。', 'Qǐng tíqián tōngzhī wǒ, rúguǒ xūyào wǒ xiézhù chǔlǐ jǐnjí shìwù.', 'Xin báo trước cho tôi nếu cần tôi hỗ trợ xử lý công việc khẩn cấp.', '[{"chinese":"提前通知","pinyin":"tíqián tōngzhī","meaning_vi":"thông báo trước"},{"chinese":"协助","pinyin":"xiézhù","meaning_vi":"hỗ trợ"},{"chinese":"紧急事务","pinyin":"jǐnjí shìwù","meaning_vi":"công việc khẩn cấp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-fcb1db5b0b4497b59597d7f9.mp3', 108),
    ('办公室考勤系统每天自动记录员工上下班时间。', 'Bàngōngshì kǎoqín xìtǒng měi tiān zìdòng jìlù yuángōng shàng xià bān shíjiān.', 'Hệ thống chấm công văn phòng tự động ghi nhận thời gian đi và về của nhân viên mỗi ngày.', '[{"chinese":"考勤系统","pinyin":"kǎoqín xìtǒng","meaning_vi":"hệ thống chấm công"},{"chinese":"自动","pinyin":"zìdòng","meaning_vi":"tự động"},{"chinese":"上下班时间","pinyin":"shàng xià bān shíjiān","meaning_vi":"thời gian đi làm và kết thúc công việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-428c5b55fb263179b7fb4b34.mp3', 109),
    ('今天因为天气原因，交通繁忙导致同事们普遍迟到。', 'Jīntiān yīnwèi tiānqì yuányīn, jiāotōng fánmáng dǎozhì tóngshìmen pǔbiàn chídào.', 'Hôm nay do thời tiết và giao thông đông đúc nên nhiều đồng nghiệp đến muộn.', '[{"chinese":"原因","pinyin":"yuányīn","meaning_vi":"nguyên nhân"},{"chinese":"交通繁忙","pinyin":"jiāotōng fánmáng","meaning_vi":"giao thông đông đúc"},{"chinese":"普遍迟到","pinyin":"pǔbiàn chídào","meaning_vi":"đi muộn phổ biến"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-fe651b76c90549874c6af88f.mp3', 110),
    ('申请调休时请提前填写相关表格并提交主管审批。', 'Shēnqǐng tiáoxiū shí qǐng tíqián tiánxiě xiāngguān biǎogé bìng tíjiāo zhǔguǎn shěnpī.', 'Khi xin đổi ngày nghỉ, xin vui lòng điền biểu mẫu liên quan và nộp cho người quản lý duyệt trước.', '[{"chinese":"调休","pinyin":"tiáoxiū","meaning_vi":"đổi ngày nghỉ"},{"chinese":"填写","pinyin":"tiánxiě","meaning_vi":"điền (vào mẫu đơn)"},{"chinese":"审批","pinyin":"shěnpī","meaning_vi":"phê duyệt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-82f95e5dc138367512a4e140.mp3', 111),
    ('提前与同事沟通，确保请假期间工作有序交接。', 'Tíqián yǔ tóngshì gōutōng, quèbǎo qǐngjià qījiān gōngzuò yǒuxù jiāojiē.', 'Liên lạc trước với đồng nghiệp để đảm bảo công việc được bàn giao trật tự trong thời gian nghỉ.', '[{"chinese":"沟通","pinyin":"gōutōng","meaning_vi":"giao tiếp, liên lạc"},{"chinese":"有序","pinyin":"yǒuxù","meaning_vi":"có trật tự"},{"chinese":"交接","pinyin":"jiāojiē","meaning_vi":"bàn giao"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8448333c14e624c69c54d21d.mp3', 112),
    ('远程办公时请保持网络畅通，确保工作效率。', 'Yuǎnchéng bàngōng shí qǐng bǎochí wǎngluò chàngtōng, quèbǎo gōngzuò xiàolǜ.', 'Khi làm việc từ xa, vui lòng giữ mạng internet thông suốt để đảm bảo hiệu quả công việc.', '[{"chinese":"远程办公","pinyin":"yuǎnchéng bàngōng","meaning_vi":"làm việc từ xa"},{"chinese":"网络畅通","pinyin":"wǎngluò chàngtōng","meaning_vi":"mạng thông suốt"},{"chinese":"工作效率","pinyin":"gōngzuò xiàolǜ","meaning_vi":"hiệu quả công việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-1f6394d595c87a8e49ef0e43.mp3', 113),
    ('加班申请请提前填写表单，注明加班时间和原因。', 'Jiābān shēnqǐng qǐng tíqián tiánxiě biǎodān, zhùmíng jiābān shíjiān hé yuányīn.', 'Xin làm đơn xin làm thêm giờ trước, ghi rõ thời gian và lý do làm thêm.', '[{"chinese":"加班申请","pinyin":"jiābān shēnqǐng","meaning_vi":"xin làm thêm giờ"},{"chinese":"表单","pinyin":"biǎodān","meaning_vi":"biểu mẫu"},{"chinese":"注明","pinyin":"zhùmíng","meaning_vi":"ghi rõ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8ffa38a4615ab291c8f38637.mp3', 114),
    ('我将在外地开会期间，通过手机保持在线处理工作事项。', 'Wǒ jiāng zài wàidì kāihuì qíjiān, tōngguò shǒujī bǎochí zàixiàn chǔlǐ gōngzuò shìxiàng.', 'Trong thời gian họp ở nơi khác, tôi sẽ giữ liên lạc qua điện thoại để xử lý công việc online.', '[{"chinese":"外地","pinyin":"wàidì","meaning_vi":"ngoài địa phương"},{"chinese":"保持在线","pinyin":"bǎochí zàixiàn","meaning_vi":"giữ kết nối online"},{"chinese":"工作事项","pinyin":"gōngzuò shìxiàng","meaning_vi":"công việc, các việc phải làm"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2d1ce5449f7b189be015e713.mp3', 115),
    ('我今晚必须加班完成客户的紧急需求。', 'Wǒ jīn wǎn bìxū jiābān wánchéng kèhù de jǐnjí xūqiú.', 'Tôi phải làm thêm giờ tối nay để hoàn thành yêu cầu khẩn cấp của khách hàng.', '[{"chinese":"加班","pinyin":"jiābān","meaning_vi":"làm thêm giờ"},{"chinese":"紧急需求","pinyin":"jǐnjí xūqiú","meaning_vi":"nhu cầu khẩn cấp"},{"chinese":"完成","pinyin":"wánchéng","meaning_vi":"hoàn thành"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-a7fc7043dd6251ee6d7976bc.mp3', 116),
    ('请各位同事准时签到，确保考勤记录准确无误。', 'Qǐng gèwèi tóngshì zhǔnshí qiāndào, quèbǎo kǎoqín jìlù zhǔnquè wúwù.', 'Mong các đồng nghiệp đến chấm công đúng giờ để đảm bảo ghi nhận công chính xác không sai sót.', '[{"chinese":"准时签到","pinyin":"zhǔnshí qiāndào","meaning_vi":"đúng giờ đăng ký (chấm công)"},{"chinese":"考勤记录","pinyin":"kǎoqín jìlù","meaning_vi":"ghi chấm công"},{"chinese":"准确无误","pinyin":"zhǔnquè wúwù","meaning_vi":"chính xác không sai sót"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-4460fd3d471831c5af6107c9.mp3', 117),
    ('完成工作交接后，请务必通知接替的同事。', 'Wánchéng gōngzuò jiāojiē hòu, qǐng wùbì tōngzhī jiētì de tóngshì.', 'Sau khi hoàn thành bàn giao công việc, xin nhớ thông báo cho đồng nghiệp tiếp nhận.', '[{"chinese":"工作交接","pinyin":"gōngzuò jiāojiē","meaning_vi":"bàn giao công việc"},{"chinese":"务必","pinyin":"wùbì","meaning_vi":"nhất định, nhớ"},{"chinese":"接替","pinyin":"jiētì","meaning_vi":"tiếp nhận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-4ee243ae01aef0660dd700d6.mp3', 118),
    ('如果要请长假，请提前一个月提交申请。', 'Rúguǒ yào qǐng chángjià, qǐng tíqián yí gè yuè tíjiāo shēnqǐng.', 'Nếu muốn xin nghỉ dài ngày, xin hãy nộp đơn trước một tháng.', '[{"chinese":"长假","pinyin":"chángjià","meaning_vi":"nghỉ dài ngày"},{"chinese":"提前","pinyin":"tíqián","meaning_vi":"trước (về mặt thời gian)"},{"chinese":"提交申请","pinyin":"tíjiāo shēnqǐng","meaning_vi":"nộp đơn xin"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-7147dcd6aea9419f73c3f6da.mp3', 119),
    ('今天下午要加班，请大家做好相关准备工作。', 'Jīntiān xiàwǔ yào jiābān, qǐng dàjiā zuò hǎo xiāngguān zhǔnbèi gōngzuò.', 'Chiều nay phải làm thêm giờ, mong mọi người chuẩn bị công việc liên quan chu đáo.', '[{"chinese":"加班","pinyin":"jiābān","meaning_vi":"làm thêm giờ"},{"chinese":"相关准备","pinyin":"xiāngguān zhǔnbèi","meaning_vi":"chuẩn bị liên quan"},{"chinese":"做好","pinyin":"zuò hǎo","meaning_vi":"làm tốt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f8bc3efc519a0bc92f554ec1.mp3', 120),
    ('参加公司外出培训期间保持积极学习状态非常重要。', 'Cānjiā gōngsī wàichū péixùn qījiān bǎochí jījí xuéxí zhuàngtài fēicháng zhòngyào.', 'Giữ thái độ học tập tích cực trong thời gian đi đào tạo ngoài công ty rất quan trọng.', '[{"chinese":"外出培训","pinyin":"wàichū péixùn","meaning_vi":"đi đào tạo bên ngoài"},{"chinese":"积极","pinyin":"jījí","meaning_vi":"tích cực"},{"chinese":"状态","pinyin":"zhuàngtài","meaning_vi":"trạng thái"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c8703a0501caf41f9f4375ed.mp3', 121),
    ('请确保加班期间的报酬及时发放，避免产生误会。', 'Qǐng quèbǎo jiābān qījiān de bàochóu jíshí fāfàng, bìmiǎn chǎnshēng wùhuì.', 'Xin đảm bảo tiền công làm thêm giờ được trả kịp thời, tránh phát sinh hiểu lầm.', '[{"chinese":"加班期间","pinyin":"jiābān qījiān","meaning_vi":"thời gian làm thêm giờ"},{"chinese":"报酬","pinyin":"bàochóu","meaning_vi":"tiền thù lao"},{"chinese":"避免","pinyin":"bìmiǎn","meaning_vi":"tránh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-10a52d80e1328f05d4ac8a10.mp3', 122),
    ('提前安排好出差行程，可以提高工作效率。', 'Tíqián ānpái hǎo chūchāi xíngchéng, kěyǐ tígāo gōngzuò xiàolǜ.', 'Sắp xếp lịch công tác trước sẽ giúp nâng cao hiệu quả công việc.', '[{"chinese":"提前安排","pinyin":"tíqián ānpái","meaning_vi":"sắp xếp trước"},{"chinese":"出差行程","pinyin":"chūchāi xíngchéng","meaning_vi":"lịch trình công tác"},{"chinese":"工作效率","pinyin":"gōngzuò xiàolǜ","meaning_vi":"hiệu quả công việc"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-f41cdb8fedb90c89162b99b7.mp3', 123),
    ('我已经提交了请假申请，请您尽快审批。', 'Wǒ yǐjīng tíjiāo le qǐngjià shēnqǐng, qǐng nín jǐnkuài shěnpī.', 'Tôi đã nộp đơn xin nghỉ phép, kính mong anh/chị phê duyệt sớm.', '[{"chinese":"请假申请","pinyin":"qǐngjià shēnqǐng","meaning_vi":"đơn xin nghỉ phép"},{"chinese":"审批","pinyin":"shěnpī","meaning_vi":"phê duyệt"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-8fdc2bbe5f523ac3d99ac542.mp3', 124),
    ('今天早上因为堵车，我来公司迟到了十分钟。', 'Jīntiān zǎoshang yīnwèi dǔchē, wǒ lái gōngsī chídào le shí fēnzhōng.', 'Sáng nay do tắc đường, tôi đến công ty muộn mười phút.', '[{"chinese":"堵车","pinyin":"dǔchē","meaning_vi":"kẹt xe, tắc đường"},{"chinese":"迟到","pinyin":"chídào","meaning_vi":"đến muộn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5a8bf5f7c0943175fe564791.mp3', 125),
    ('请在邮件主题中明确标注会议的时间和地点。', 'Qǐng zài yóujiàn zhǔtí zhōng míngquè biāozhù huìyì de shíjiān hé dìdiǎn.', 'Vui lòng ghi rõ thời gian và địa điểm cuộc họp trong tiêu đề email.', '[{"chinese":"邮件主题","pinyin":"yóujiàn zhǔtí","meaning_vi":"tiêu đề email"},{"chinese":"明确","pinyin":"míngquè","meaning_vi":"rõ ràng, minh bạch"},{"chinese":"标注","pinyin":"biāozhù","meaning_vi":"đánh dấu, chú thích"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-c5b7b868044d13f73d3a458d.mp3', 126),
    ('发送邮件时请注意不要把附件发送给错误的收件人。', 'Fāsòng yóujiàn shí qǐng zhùyì bú yào bǎ fùjiàn fāsòng gěi cuòwù de shōujiànrén.', 'Khi gửi email hãy chú ý không gửi tệp đính kèm cho người nhận sai.', '[{"chinese":"附件","pinyin":"fùjiàn","meaning_vi":"tệp đính kèm"},{"chinese":"错误","pinyin":"cuòwù","meaning_vi":"sai, lỗi"},{"chinese":"收件人","pinyin":"shōujiànrén","meaning_vi":"người nhận thư"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-514b78d3cb34796bf3ef0c15.mp3', 127),
    ('请尽快回复邮件，以免影响项目的进展。', 'Qǐng jǐnkuài huífù yóujiàn, yǐmiǎn yǐngxiǎng xiàngmù de jìnzhǎn.', 'Vui lòng trả lời email càng sớm càng tốt để tránh ảnh hưởng tiến độ dự án.', '[{"chinese":"回复","pinyin":"huífù","meaning_vi":"phản hồi, trả lời"},{"chinese":"以免","pinyin":"yǐmiǎn","meaning_vi":"để tránh"},{"chinese":"进展","pinyin":"jìnzhǎn","meaning_vi":"tiến triển, tiến độ"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-71160263527213a9d7489a66.mp3', 128),
    ('请将最新的项目文件附加在邮件中发送给相关部门。', 'Qǐng jiāng zuìxīn de xiàngmù wénjiàn fùjiā zài yóujiàn zhōng fāsòng gěi xiāngguān bùmén.', 'Vui lòng đính kèm tài liệu dự án mới nhất trong email gửi cho các phòng ban liên quan.', '[{"chinese":"最新","pinyin":"zuìxīn","meaning_vi":"mới nhất"},{"chinese":"附加","pinyin":"fùjiā","meaning_vi":"đính kèm"},{"chinese":"相关部门","pinyin":"xiāngguān bùmén","meaning_vi":"phòng ban liên quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-4b15e23be24fede6338088b6.mp3', 129),
    ('错误发送邮件后，应立即说明情况并通知正确的接收人。', 'Cuòwù fāsòng yóujiàn hòu, yīng lìjí shuōmíng qíngkuàng bìng tōngzhī zhèngquè de jiēshōu rén.', 'Sau khi gửi nhầm email, cần ngay lập tức giải thích tình hình và thông báo cho người nhận đúng.', '[{"chinese":"错误","pinyin":"cuòwù","meaning_vi":"sai, lỗi"},{"chinese":"说明","pinyin":"shuōmíng","meaning_vi":"giải thích"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d5ad96ec15d0fcb8cb125189.mp3', 130),
    ('请提醒同事及时处理未回复的邮件和任务。', 'Qǐng tíxǐng tóngshì jíshí chǔlǐ wèi huífù de yóujiàn hé rènwù.', 'Hãy nhắc nhở đồng nghiệp xử lý kịp thời các email và nhiệm vụ chưa được trả lời.', '[{"chinese":"提醒","pinyin":"tíxǐng","meaning_vi":"nhắc nhở"},{"chinese":"及时","pinyin":"jíshí","meaning_vi":"kịp thời"},{"chinese":"处理","pinyin":"chǔlǐ","meaning_vi":"xử lý"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-72775667f27de062bf406ab5.mp3', 131),
    ('请在邮件中添加相关人员为抄送收件人，保持信息透明。', 'Qǐng zài yóujiàn zhōng tiānjiā xiāngguān rényuán wéi chāosòng shōujiànrén, bǎochí xìnxī tòumíng.', 'Vui lòng thêm người liên quan vào phần cc trong email để duy trì sự minh bạch thông tin.', '[{"chinese":"抄送","pinyin":"chāosòng","meaning_vi":"cc, gửi bản sao"},{"chinese":"相关人员","pinyin":"xiāngguān rényuán","meaning_vi":"người liên quan"},{"chinese":"透明","pinyin":"tòumíng","meaning_vi":"minh bạch"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-414835654e644ed92b0485b8.mp3', 132),
    ('请跨部门协调，确保项目进度按时完成。', 'Qǐng kuà bùmén xiétiáo, quèbǎo xiàngmù jìndù ànshí wánchéng.', 'Vui lòng phối hợp liên phòng ban để đảm bảo tiến độ dự án hoàn thành đúng hạn.', '[{"chinese":"跨部门","pinyin":"kuà bùmén","meaning_vi":"liên phòng ban"},{"chinese":"协调","pinyin":"xiétiáo","meaning_vi":"phối hợp"},{"chinese":"按时","pinyin":"ànshí","meaning_vi":"đúng hạn"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-3ebbda4ebcf87ddd1a243c8e.mp3', 133),
    ('感谢您的反馈，我会根据意见调整工作计划。', 'Gǎnxiè nín de fǎnkuì, wǒ huì gēnjù yìjiàn tiáozhěng gōngzuò jìhuà.', 'Cảm ơn phản hồi của bạn, tôi sẽ điều chỉnh kế hoạch công việc dựa trên ý kiến đó.', '[{"chinese":"反馈","pinyin":"fǎnkuì","meaning_vi":"phản hồi"},{"chinese":"根据","pinyin":"gēnjù","meaning_vi":"dựa theo"},{"chinese":"调整","pinyin":"tiáozhěng","meaning_vi":"điều chỉnh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-13882ad2ccb1e83c4dbeaa72.mp3', 134),
    ('请及时更新共享文档，确保团队信息一致。', 'Qǐng jíshí gēngxīn gòngxiǎng wéndàng, quèbǎo tuánduì xìnxī yízhì.', 'Vui lòng cập nhật tài liệu chia sẻ kịp thời để đảm bảo thông tin trong nhóm nhất quán.', '[{"chinese":"更新","pinyin":"gēngxīn","meaning_vi":"cập nhật"},{"chinese":"共享文档","pinyin":"gòngxiǎng wéndàng","meaning_vi":"tài liệu chia sẻ"},{"chinese":"确保","pinyin":"quèbǎo","meaning_vi":"đảm bảo"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5481e9d18e2b1ae5870330d7.mp3', 135),
    ('请在邮件中书面确认会议的时间和议程安排。', 'Qǐng zài yóujiàn zhōng shūmiàn quèrèn huìyì de shíjiān hé yìchéng ānpái.', 'Vui lòng xác nhận bằng văn bản thời gian và chương trình cuộc họp trong email.', '[{"chinese":"书面确认","pinyin":"shūmiàn quèrèn","meaning_vi":"xác nhận bằng văn bản"},{"chinese":"议程","pinyin":"yìchéng","meaning_vi":"chương trình, lịch trình"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-bd6945fa614450ea195b81b6.mp3', 136),
    ('我已经将需要的文件通过邮件发送给您，请查收。', 'Wǒ yǐjīng jiāng xūyào de wénjiàn tōngguò yóujiàn fāsòng gěi nín, qǐng cháshōu.', 'Tôi đã gửi cho bạn tài liệu cần thiết qua email, vui lòng kiểm tra.', '[{"chinese":"文件","pinyin":"wénjiàn","meaning_vi":"tài liệu"},{"chinese":"通过","pinyin":"tōngguò","meaning_vi":"thông qua"},{"chinese":"查收","pinyin":"cháshōu","meaning_vi":"kiểm tra và nhận"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-4e24e4cd487f599eec6748b6.mp3', 137),
    ('请在群聊中及时发布项目最新进展的通知。', 'Qǐng zài qúnliáo zhōng jíshí fābù xiàngmù zuìxīn jìnzhǎn de tōngzhī.', 'Vui lòng đăng thông báo cập nhật tiến độ dự án mới nhất trong nhóm chat kịp thời.', '[{"chinese":"群聊","pinyin":"qúnliáo","meaning_vi":"nhóm chat"},{"chinese":"发布","pinyin":"fābù","meaning_vi":"phát hành, đăng"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-91eecdededf565fd807ef990.mp3', 138),
    ('请确保所有发送的文件均已按要求妥善命名。', 'Qǐng quèbǎo suǒyǒu fāsòng de wénjiàn jūn yǐ àn yāoqiú tuǒshàn mìngmíng.', 'Vui lòng đảm bảo tất cả các tài liệu gửi đi đều được đặt tên đúng theo yêu cầu.', '[{"chinese":"妥善","pinyin":"tuǒshàn","meaning_vi":"thỏa đáng, phù hợp"},{"chinese":"命名","pinyin":"mìngmíng","meaning_vi":"đặt tên"},{"chinese":"按要求","pinyin":"àn yāoqiú","meaning_vi":"theo yêu cầu"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-31dab89f004e58662442e37b.mp3', 139),
    ('请将会议纪要整理后，通过邮件分发给各相关部门。', 'Qǐng jiāng huìyì jìyào zhěnglǐ hòu, tōngguò yóujiàn fēnfā gěi gè xiāngguān bùmén.', 'Vui lòng sau khi tổng hợp biên bản họp thì phát qua email tới các phòng liên quan.', '[{"chinese":"会议纪要","pinyin":"huìyì jìyào","meaning_vi":"biên bản họp"},{"chinese":"整理","pinyin":"zhěnglǐ","meaning_vi":"sắp xếp, tổng hợp"},{"chinese":"分发","pinyin":"fēnfā","meaning_vi":"phân phát"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-dee91b97692f1c5cbc7c303b.mp3', 140),
    ('请在确认完成工作后，及时通知相关负责人备案。', 'Qǐng zài quèrèn wánchéng gōngzuò hòu, jíshí tōngzhī xiāngguān fùzérén bèi''àn.', 'Vui lòng sau khi xác nhận hoàn thành công việc hãy kịp thời thông báo người phụ trách liên quan để lưu trữ.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"负责人","pinyin":"fùzérén","meaning_vi":"người chịu trách nhiệm"},{"chinese":"备案","pinyin":"bèi''àn","meaning_vi":"lưu trữ, ghi biên bản"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-84ea072546606d0e15c4deee.mp3', 141),
    ('请将任务分解并合理分配给团队成员，确保效率。', 'Qǐng jiāng rènwù fēnjiě bìng hélǐ fēnpèi gěi tuánduì chéngyuán, quèbǎo xiàolǜ.', 'Hãy chia nhỏ và phân công nhiệm vụ hợp lý cho các thành viên để bảo đảm hiệu quả.', '[{"chinese":"分解","pinyin":"fēnjiě","meaning_vi":"phân giải, phân tích"},{"chinese":"合理","pinyin":"hélǐ","meaning_vi":"hợp lý"},{"chinese":"分配","pinyin":"fēnpèi","meaning_vi":"phân phối"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-55426a57dbeba169b0dba26d.mp3', 142),
    ('请将紧急事项优先处理并及时向我反馈进展情况。', 'Qǐng jiāng jǐnjí shìxiàng yōuxiān chǔlǐ bìng jíshí xiàng wǒ fǎnkuì jìnzhǎn qíngkuàng.', 'Vui lòng ưu tiên xử lý các vấn đề khẩn cấp và kịp thời phản hồi tình hình tiến độ cho tôi.', '[{"chinese":"紧急事项","pinyin":"jǐnjí shìxiàng","meaning_vi":"vấn đề khẩn cấp"},{"chinese":"优先","pinyin":"yōuxiān","meaning_vi":"ưu tiên"},{"chinese":"反馈","pinyin":"fǎnkuì","meaning_vi":"phản hồi"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-7c66af54f5d48bbffa03166b.mp3', 143),
    ('收到您的邮件，我会尽快安排对接相关工作。', 'Shōudào nín de yóujiàn, wǒ huì jǐnkuài ānpái duìjiē xiāngguān gōngzuò.', 'Tôi đã nhận được email và sẽ sớm sắp xếp người phối hợp công việc liên quan.', '[{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"},{"chinese":"对接","pinyin":"duìjiē","meaning_vi":"đối nối, kết nối"},{"chinese":"相关","pinyin":"xiāngguān","meaning_vi":"liên quan"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-d331c87b204aefddf2e88210.mp3', 144),
    ('请确认是否所有附件均已成功上传至共享平台。', 'Qǐng quèrèn shìfǒu suǒyǒu fùjiàn jūn yǐ chénggōng shàngchuán zhì gòngxiǎng píngtái.', 'Vui lòng xác nhận tất cả các tệp đính kèm đã được tải lên thành công trên nền tảng chia sẻ chưa.', '[{"chinese":"附件","pinyin":"fùjiàn","meaning_vi":"tệp đính kèm"},{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"上传","pinyin":"shàngchuán","meaning_vi":"tải lên"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2c50016f46f91e9722128a01.mp3', 145),
    ('请利用邮件功能，及时通知团队成员最新工作安排。', 'Qǐng lìyòng yóujiàn gōngnéng, jíshí tōngzhī tuánduì chéngyuán zuìxīn gōngzuò ānpái.', 'Hãy sử dụng chức năng email để kịp thời thông báo lịch công việc mới nhất cho các thành viên trong nhóm.', '[{"chinese":"功能","pinyin":"gōngnéng","meaning_vi":"chức năng"},{"chinese":"通知","pinyin":"tōngzhī","meaning_vi":"thông báo"},{"chinese":"安排","pinyin":"ānpái","meaning_vi":"sắp xếp"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-6deb4ab999b0014389a0c6b0.mp3', 146),
    ('请及时回复客户的邮件，体现专业与效率。', 'Qǐng jíshí huífù kèhù de yóujiàn, tǐxiàn zhuānyè yǔ xiàolǜ.', 'Hãy trả lời email khách hàng kịp thời để thể hiện sự chuyên nghiệp và hiệu quả.', '[{"chinese":"客户","pinyin":"kèhù","meaning_vi":"khách hàng"},{"chinese":"体现","pinyin":"tǐxiàn","meaning_vi":"thể hiện"},{"chinese":"效率","pinyin":"xiàolǜ","meaning_vi":"hiệu quả"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-44db51eec4c06aa7d57710dc.mp3', 147),
    ('请遵守邮件礼仪，避免使用过于随意的语言。', 'Qǐng zūnshǒu yóujiàn lǐyí, bìmiǎn shǐyòng guòyú suíyì de yǔyán.', 'Vui lòng tuân thủ phép lịch sự khi viết email và tránh dùng ngôn ngữ quá tùy tiện.', '[{"chinese":"遵守","pinyin":"zūnshǒu","meaning_vi":"tuân thủ"},{"chinese":"礼仪","pinyin":"lǐyí","meaning_vi":"lễ nghi"},{"chinese":"避免","pinyin":"bìmiǎn","meaning_vi":"tránh"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-47aec7739116b68a19dfefc5.mp3', 148),
    ('请各位同事确认会议纪要的内容是否准确无误。', 'Qǐng gèwèi tóngshì quèrèn huìyì jìyào de nèiróng shìfǒu zhǔnquè wúwù.', 'Mọi người vui lòng xác nhận nội dung biên bản họp có chính xác hay không.', '[{"chinese":"确认","pinyin":"quèrèn","meaning_vi":"xác nhận"},{"chinese":"会议纪要","pinyin":"huìyì jìyào","meaning_vi":"biên bản họp"},{"chinese":"准确无误","pinyin":"zhǔnquè wúwù","meaning_vi":"chính xác không sai sót"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-5f605b52c18469587e4ff560.mp3', 149),
    ('请提前将会议议题发送给与会人员做好准备。', 'Qǐng tíqián jiāng huìyì yìtí fāsòng gěi yùhuì rényuán zuò hǎo zhǔnbèi.', 'Vui lòng gửi trước các nội dung họp cho người tham dự để họ chuẩn bị tốt.', '[{"chinese":"提前","pinyin":"tíqián","meaning_vi":"trước thời hạn"},{"chinese":"议题","pinyin":"yìtí","meaning_vi":"nội dung họp"},{"chinese":"与会人员","pinyin":"yùhuì rényuán","meaning_vi":"người tham dự"}]', 'https://ssmqppvkgffknfqdvpwg.supabase.co/storage/v1/object/public/card-audio/templates/giao-tiep-cong-so-150-cau/sentence-2152af04eb67f82d36f16ead.mp3', 150)
) as card(
  sentence_cn, sentence_pinyin, sentence_vi,
  vocab_json, sentence_audio_url, position
)
on conflict (template_deck_id, sentence_cn) do update
set
  sentence_pinyin = excluded.sentence_pinyin,
  sentence_vi = excluded.sentence_vi,
  vocab_json = excluded.vocab_json,
  sentence_audio_url = excluded.sentence_audio_url,
  position = excluded.position;

delete from public.template_sentence_cards
where template_deck_id = (
  select id from public.template_decks where slug = 'giao-tiep-cong-so-150-cau'
